// ── Helpers ──────────────────────────────────────────────────────────────────

export const masteryTreeByWeapon = (weaponName: string): WeaponMasteryTree | undefined =>
  MASTERY_TREES.find(t => t.weapon_name.toLowerCase() === weaponName.toLowerCase())

export const masteryNodeById = (id: number): MasteryNode | undefined =>
  MASTERY_TREES.flatMap(t => t.nodes).find(n => n.id === id)

export const skillNodesForWeapon = (weaponName: string): MasteryNode[] =>
  masteryTreeByWeapon(weaponName)?.nodes.filter(n => n.isSkillNode) ?? []
